const since = new Date($node["Set Since Date"].json["since_date"]);
return $input.first().json.data.posts.edges
  .map(edge => ({ json: edge.node }))
  .filter(item => new Date(item.json.featuredAt) > since);

return $input.all().flatMap(item => {
  const post = item.json;
  return post.makers.map(maker => ({ json: { post, maker } }));
});

const timestamps = $input.all().map(item => new Date(item.json.post.featuredAt).getTime());
const maxTime = Math.max(...timestamps);
return [{ json: { max_featuredAt: new Date(maxTime).toISOString() } }];
